export const WALK_2K_MAX_SEC = [{"bracket": "<30", "male_max": 976, "female_max": 1042}, {"bracket": "30-39", "male_max": 978, "female_max": 1048}, {"bracket": "40-49", "male_max": 983, "female_max": 1069}, {"bracket": "50-59", "male_max": 1000, "female_max": 1091}, {"bracket": "60+", "male_max": 1018, "female_max": 1133}] as const;

export function getPFRAAgeBracket(ageYears: number): PFRAAgeBracket {
  if (ageYears < 25) return 'under25';
  if (ageYears < 30) return '25-29';
  if (ageYears < 35) return '30-34';
  if (ageYears < 40) return '35-39';
  if (ageYears < 45) return '40-44';
  if (ageYears < 50) return '45-49';
  if (ageYears < 55) return '50-54';
  if (ageYears < 60) return '55-59';
  return '60+';
}

export function getWalkAgeBracket(ageYears: number): WalkAgeBracket {
  if (ageYears < 30) return '<30';
  if (ageYears < 40) return '30-39';
  if (ageYears < 50) return '40-49';
  if (ageYears < 60) return '50-59';
  return '60+';
}

export function passesWalk2k(ageYears: number, gender: Gender, valueSec: number): boolean {
  const bracket = getWalkAgeBracket(ageYears);
  const row = (WALK_2K_MAX_SEC as any).find((r: any) => r.bracket === bracket);
  if (!row) return false;
  const maxSec = gender === 'male' ? row.male_max : row.female_max;
  return valueSec <= maxSec;
}

function scoreHigherIsBetter<T extends number>(rows: readonly PointsRow<T>[], age: PFRAAgeBracket, gender: Gender, value: number): number {
  const minimumRow = rows[rows.length - 1];
  const minimumThreshold = minimumRow.thresholds[age][gender];

  // The official charts can include a starred minimum passing threshold that is
  // numerically identical to the next higher score threshold. In that case, an
  // exact match at the minimum must still score as the minimum passing value.
  if (value === minimumThreshold) return minimumRow.points;

  for (const row of rows) {
    const thr = row.thresholds[age][gender];
    if (value >= thr) return row.points;
  }
  return 0;
}

function scoreLowerIsBetter<T extends number>(rows: readonly PointsRow<T>[], age: PFRAAgeBracket, gender: Gender, value: number): number {
  for (const row of rows) {
    const thr = row.thresholds[age][gender];
    if (value <= thr) return row.points;
  }
  return 0;
}

export function scoreWHtR(waistIn: number, heightIn: number): number {
  if (heightIn <= 0) return 0;
  const ratio = waistIn / heightIn;
  // Lower is better; chart uses <= thresholds down to 0.49 for 20.0 points.
  for (const row of WHtR_ROWS) {
    if (ratio <= row.ratio) return row.points;
  }
  return 0;
}

export function scoreStrength(ageYears: number, gender: Gender, test: 'pushups' | 'hand_release_pushups', reps: number): number {
  const age = getPFRAAgeBracket(ageYears);
  const rows = test === 'pushups' ? PUSHUP_ROWS : HAND_RELEASE_PUSHUP_ROWS;
  return scoreHigherIsBetter(rows as any, age, gender, reps);
}

export function scoreCore(ageYears: number, gender: Gender, test: 'situps' | 'cross_leg_reverse_crunch' | 'plank', value: number): number {
  const age = getPFRAAgeBracket(ageYears);
  if (test === 'plank') return scoreHigherIsBetter(PLANK_ROWS_SEC as any, age, gender, value);
  const rows = test === 'situps' ? SITUP_ROWS : REVERSE_CRUNCH_ROWS;
  return scoreHigherIsBetter(rows as any, age, gender, value);
}

export function scoreCardio(ageYears: number, gender: Gender, test: 'run_2mile' | 'hamr_20m' | 'walk_2k', value: number): number {
  if (test === 'walk_2k') {
    // Official chart is pass/fail only, so there is no numeric cardio score to return.
    return 0;
  }
  const age = getPFRAAgeBracket(ageYears);
  if (test === 'run_2mile') return scoreLowerIsBetter(RUN_2MILE_ROWS_SEC as any, age, gender, value);
  return scoreHigherIsBetter(HAMR_20M_ROWS as any, age, gender, value);
}

export const PFRA_MINIMUM_COMPONENT_POINTS = {
  waist: 2.5,
  strength: 2.5,
  core: 2.5,
  cardio: 35.0,
} as const;

export type ScoreBreakdown = { waist: number; strength: number; core: number; cardio: number; total: number };

export function scoreTotal(params: { ageYears: number; gender: Gender; waistIn: number; heightIn: number; strengthTest: 'pushups' | 'hand_release_pushups'; strengthReps: number; coreTest: 'situps' | 'cross_leg_reverse_crunch' | 'plank'; coreValue: number; cardioTest: 'run_2mile' | 'hamr_20m' | 'walk_2k'; cardioValue: number; }): ScoreBreakdown {
  const waist = scoreWHtR(params.waistIn, params.heightIn);
  const strength = scoreStrength(params.ageYears, params.gender, params.strengthTest, params.strengthReps);
  const core = scoreCore(params.ageYears, params.gender, params.coreTest, params.coreValue);
  const cardio = scoreCardio(params.ageYears, params.gender, params.cardioTest, params.cardioValue);
  return { waist, strength, core, cardio, total: waist + strength + core + cardio };
}

export function meetsPFRAComponentMinimums(scores: Pick<ScoreBreakdown, 'waist' | 'strength' | 'core' | 'cardio'>): boolean {
  return (
    scores.waist >= PFRA_MINIMUM_COMPONENT_POINTS.waist &&
    scores.strength >= PFRA_MINIMUM_COMPONENT_POINTS.strength &&
    scores.core >= PFRA_MINIMUM_COMPONENT_POINTS.core &&
    scores.cardio >= PFRA_MINIMUM_COMPONENT_POINTS.cardio
  );
}
